266	    -- ... Cannot be moved to a package because VHDL93 (supported by all tools) does not allow
267	    -- ... unconstrainted arrays as return types.
268	    function getInitContent return Data_t is
269	        variable Data_v         : Data_t(Depth_g - 1 downto 0)               := (others => (others => '0'));
270	        constant InitElements_c : natural                                    := countOccurence(InitString_g, ',')+1;
271	        variable StartIdx_v     : natural                                    := InitString_g'left;
272	        variable EndIdx_v       : natural;
273	        variable FullInitVal_v  : std_logic_vector(InitWidth_g - 1 downto 0) := (others => '0');
274	    begin
275	        if InitFormat_g /= "NONE" then
276	
277	            -- Loop through elements
278	            for i in 0 to InitElements_c - 1 loop
279	                EndIdx_v := StartIdx_v;
280	
281	                -- Find end of element
282	                loop
283	                    if InitString_g(EndIdx_v) = ',' then
284	                        EndIdx_v := EndIdx_v - 1;
285	                        exit;
286	                    end if;
287	                    if EndIdx_v = InitString_g'right then
288	                        exit;
289	                    end if;
290	                    EndIdx_v := EndIdx_v + 1;
291	                end loop;
292	
293	                FullInitVal_v := hex2StdLogicVector(InitString_g(StartIdx_v to EndIdx_v), InitWidth_g, hasPrefix => true);
294	                Data_v(i)     := FullInitVal_v(InitShift_g + Width_g - 1 downto InitShift_g);
295	                StartIdx_v    := EndIdx_v + 2;
296	
297	            end loop;
298	
299	        end if;
