344	                    end if;
345	                end if;
346	
347	                -- Read-data pipeline registers
348	                RdPipe(2 to RdLatency_g) <= RdPipe(1 to RdLatency_g-1);
349	            end if;
350	        end process;
351	
352	    end generate;
353	
354	    -- Asynchronous implementation
355	    g_async : if IsAsync_g generate
356	
357	        -- Write side
358	        p_write : process (Clk) is
359	        begin
360	            if rising_edge(Clk) then
361	                if Wr_Ena = '1' then
362	                    Mem_v(to_integer(unsigned(Wr_Addr))) := Wr_Data;
363	                end if;
364	            end if;
365	        end process;
366	
367	        -- Read side
