-- vunit: run_all_in_same_sim
entity olo_base_ram_sdp_tb is
    generic (
        runner_cfg      : string;
        Width_g         : positive range 5 to 128 := 32;
        RamBehavior_g   : string                  := "RBW";
        UseByteEnable_g : boolean                 := false;
        IsAsync_g       : boolean                 := false;
        RdLatency_g     : positive range 1 to 2   := 1;
        InitFormat_g    : string                  := "NONE"
    );
end entity;

architecture sim of olo_base_ram_sdp_tb is

    -----------------------------------------------------------------------------------------------
    -- Constants
    -----------------------------------------------------------------------------------------------
    constant InitString_c  : string  := "0x01, 0x5,0x1317";
    constant BeWidth_c     : integer := Width_g/8;
    constant BeSigWidth_c  : integer := maximum(BeWidth_c, 2); -- Must be at least 2 bits to avoid compile errors with GHDL.
    -- .. GHDL checks ranges also on code in a not executed if-clause.
    constant ClkPeriod_c   : time := 10 ns;
    constant RdClkPeriod_c : time := 33.3 ns;

    -----------------------------------------------------------------------------------------------
    -- TB Defnitions
    -----------------------------------------------------------------------------------------------
    procedure write (
        address       : natural;
        data          : natural;
        signal Clk    : in std_logic;
        signal Addr   : out std_logic_vector;
        signal WrData : out std_logic_vector;
        signal WrEna  : out std_logic) is
    begin
        wait until rising_edge(Clk);
        Addr   <= toUslv(address, Addr'length);
        WrData <= toUslv(data, WrData'length);
        WrEna  <= '1';
        wait until rising_edge(Clk);
        WrEna  <= '0';
        Addr   <= toUslv(0, Addr'length);
        WrData <= toUslv(0, WrData'length);
    end procedure;

    procedure check (
        address       : natural;
        data          : natural;
        signal Clk    : in std_logic;
        signal Addr   : out std_logic_vector;
        signal RdData : in std_logic_vector;
        message       : string) is
    begin
        wait until rising_edge(Clk);
        Addr <= toUslv(address, Addr'length);
        wait until rising_edge(Clk); -- Address sampled
        Addr <= toUslv(0, Addr'length);

        -- Wait for read data to arrive
        for i in 1 to RdLatency_g loop
            wait until rising_edge(Clk);
        end loop;

        check_equal(RdData, toUslv(data, RdData'length), message);
    end procedure;

    -----------------------------------------------------------------------------------------------
    -- Interface Signals
    -----------------------------------------------------------------------------------------------
    signal Clk      : std_logic                                 := '0';
    signal Rst      : std_logic                                 := '0';
    signal Wr_Addr  : std_logic_vector(7 downto 0)              := (others => '0');
    signal Wr_Ena   : std_logic                                 := '0';
    signal Wr_Be    : std_logic_vector(BeSigWidth_c-1 downto 0) := (others => '1');
    signal Wr_Data  : std_logic_vector(Width_g - 1 downto 0)    := (others => '0');
    signal Rd_Clk   : std_logic                                 := '0';
    signal Rd_Rst   : std_logic                                 := '0';
    signal Rd_Addr  : std_logic_vector(7 downto 0)              := (others => '0');
    signal Rd_Ena   : std_logic                                 := '1';
    signal Rd_Data  : std_logic_vector(Width_g - 1 downto 0)    := (others => '0');
    signal Rd_Valid : std_logic                                 := '0';

begin

    -----------------------------------------------------------------------------------------------
    -- DUT
    -----------------------------------------------------------------------------------------------
    i_dut : entity olo.olo_base_ram_sdp
        generic map (
            Depth_g         => 200,
            Width_g         => Width_g,
            RamBehavior_g   => RamBehavior_g,
            UseByteEnable_g => UseByteEnable_g,
            IsAsync_g       => IsAsync_g,
            RdLatency_g     => RdLatency_g,
            InitString_g    => InitString_c,
            InitFormat_g    => InitFormat_g

    named_config(tb, {'ReadyRstState_g': ReadyRst})
for RandomStall in [True, False]:
    named_config(tb, {'RandomStall_g': RandomStall})


### olo_base_cc_... sync ###
scc_tbs = ['olo_base_cc_xn2n_tb', 'olo_base_cc_n2xn_tb']
for tb_name in scc_tbs:
    tb = olo_tb.test_bench(tb_name)
    for R in [2, 3, 19]:
        named_config(tb, {'ClockRatio_g': R})

### olo_base_ram_... ###
ram_tbs = ['olo_base_ram_sp_tb', 'olo_base_ram_tdp_tb', 'olo_base_ram_sdp_tb']
for tb_name in ram_tbs:
    tb = olo_tb.test_bench(tb_name)
    for RamBehav in ['RBW', 'WBR']:
        named_config(tb, {'RamBehavior_g': RamBehav})
        if tb_name == "olo_base_ram_sdp_tb":
            for Async in [True, False]:
                named_config(tb, {'RamBehavior_g': RamBehav, "IsAsync_g": Async})
    for ReadLatency in [1, 2]:
        named_config(tb, {"RdLatency_g": ReadLatency})
    for Width in [5, 32]:
        named_config(tb, {'Width_g': Width})
    for Be in [True, False]:
        named_config(tb, {'Width_g': 32, 'UseByteEnable_g' : Be})
    # Check no-init
    named_config(tb, {'InitFormat_g': 'NONE'})
    # Check non byte-width
    named_config(tb, {'InitFormat_g': 'HEX', 'Width_g': 7})
    # Check init, byte-enables play a role internally
    for Be in [True, False]:
        for Width in [8, 16]: 
            named_config(tb, {'InitFormat_g': 'HEX', 'Width_g': Width, 'UseByteEnable_g' : Be})

### olo_base_fifo_... non-packet ###
fifo_tbs = ['olo_base_fifo_sync_tb', 'olo_base_fifo_async_tb']
for tb_name in fifo_tbs:
    tb = olo_tb.test_bench(tb_name)

